using Microsoft.VisualStudio.TestTools.UnitTesting;
using Store;

namespace Store.Tests;

[TestClass]
public class ShoppingCartTests
{
    private ShoppingCart _cart = null!;

    [TestInitialize]
    public void Setup()
    {
        _cart = new ShoppingCart();
    }

    // ── AddItem ──────────────────────────────────────────────

    [TestMethod]
    public void AddItem_SingleItem_DoesNotThrow()
    {
        _cart.AddItem("SKU-001", 1, 9.99m);
    }

    [TestMethod]
    public void AddItem_MultipleDistinctItems_DoesNotThrow()
    {
        _cart.AddItem("SKU-001", 1, 9.99m);
        _cart.AddItem("SKU-002", 3, 4.50m);
        _cart.AddItem("SKU-003", 2, 15.00m);
    }

    [TestMethod]
    public void AddItem_DuplicateSku_DoesNotThrow()
    {
        _cart.AddItem("SKU-001", 1, 9.99m);
        _cart.AddItem("SKU-001", 2, 9.99m);
    }

    // ── RemoveItem ───────────────────────────────────────────

    [TestMethod]
    public void RemoveItem_ExistingItem_DoesNotThrow()
    {
        _cart.AddItem("SKU-001", 1, 9.99m);
        _cart.RemoveItem("SKU-001");
    }

    [TestMethod]
    public void RemoveItem_NonExistentItem_DoesNotThrow()
    {
        _cart.RemoveItem("SKU-MISSING");
    }

    [TestMethod]
    public void RemoveItem_AfterRemoval_ItemNotInTotal()
    {
        _cart.AddItem("SKU-001", 1, 10.00m);
        _cart.AddItem("SKU-002", 1, 5.00m);
        _cart.RemoveItem("SKU-001");

        Assert.AreEqual(5.00m, _cart.CalculateTotal());
    }

    // ── CalculateTotal ───────────────────────────────────────

    [TestMethod]
    public void CalculateTotal_EmptyCart_ReturnsZero()
    {
        Assert.AreEqual(0m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_SingleItem_ReturnsPriceTimesQuantity()
    {
        _cart.AddItem("SKU-001", 3, 10.00m);

        Assert.AreEqual(30.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_MultipleItems_ReturnsSumOfLineItems()
    {
        _cart.AddItem("SKU-001", 2, 10.00m); // 20.00
        _cart.AddItem("SKU-002", 1, 5.50m);  //  5.50
        _cart.AddItem("SKU-003", 4, 1.25m);  //  5.00

        Assert.AreEqual(30.50m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_AfterAddAndRemove_ReflectsCurrentItems()
    {
        _cart.AddItem("SKU-001", 1, 20.00m);
        _cart.AddItem("SKU-002", 1, 15.00m);
        _cart.RemoveItem("SKU-002");

        Assert.AreEqual(20.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_AllItemsRemoved_ReturnsZero()
    {
        _cart.AddItem("SKU-001", 1, 10.00m);
        _cart.RemoveItem("SKU-001");

        Assert.AreEqual(0m, _cart.CalculateTotal());
    }

    // ── ApplyCoupon ──────────────────────────────────────────

    [TestMethod]
    public void ApplyCoupon_ValidCode_DoesNotThrow()
    {
        _cart.AddItem("SKU-001", 1, 50.00m);
        _cart.ApplyCoupon("SAVE10");
    }

    [TestMethod]
    public void ApplyCoupon_ReducesTotal()
    {
        _cart.AddItem("SKU-001", 1, 100.00m);
        _cart.ApplyCoupon("SAVE10");

        var total = _cart.CalculateTotal();
        Assert.IsTrue(total < 100.00m, $"Expected discounted total < 100, but was {total}");
    }

    [TestMethod]
    public void ApplyCoupon_InvalidCode_ThrowsException()
    {
        _cart.AddItem("SKU-001", 1, 50.00m);
        Assert.ThrowsException<ArgumentException>(() => _cart.ApplyCoupon("INVALID-COUPON"));
    }

    [TestMethod]
    public void ApplyCoupon_TotalNeverNegative()
    {
        _cart.AddItem("SKU-001", 1, 1.00m);
        _cart.ApplyCoupon("SAVE10");

        var total = _cart.CalculateTotal();
        Assert.IsTrue(total >= 0m, $"Total should never be negative, but was {total}");
    }

    // ── Integration / edge cases ─────────────────────────────

    [TestMethod]
    public void CalculateTotal_CalledMultipleTimes_ReturnsSameValue()
    {
        _cart.AddItem("SKU-001", 2, 7.50m);

        var first = _cart.CalculateTotal();
        var second = _cart.CalculateTotal();

        Assert.AreEqual(first, second);
    }

    [TestMethod]
    public void AddItem_ThenCoupon_ThenRemove_TotalIsCorrect()
    {
        _cart.AddItem("SKU-001", 1, 100.00m);
        _cart.AddItem("SKU-002", 1, 50.00m);
        _cart.ApplyCoupon("SAVE10");
        _cart.RemoveItem("SKU-002");

        var total = _cart.CalculateTotal();
        Assert.IsTrue(total < 100.00m, $"Expected discounted total < 100, but was {total}");
        Assert.IsTrue(total > 0m);
    }
}

